   194→      if (title) args.push('--title', title)
   195→      if (description !== undefined) args.push('--description', description)
   196→      if (priority !== undefined) args.push('--priority', String(priority))
   197→      await spawnBdCommand(args, { cwd })
   198→      return { success: true }
   199→    } catch (e: any) {
   200→      return { success: false, error: e.message }
   201→    }
   202→  })
   203→
   204→  ipcMain.handle('beads:install', async () => {
   205→    try {
   206→      beadsAvailable = null
   207→      const result = await installBeadsBinary((status, percent) => {
   208→        getMainWindow()?.webContents.send('install:progress', { type: 'beads', status, percent })
   209→      })
   210→      if (result.success) {
   211→        const portableDirs = getPortableBinDirs()
   212→        setPortableBinDirs(portableDirs)
   213→        const installed = await checkBeadsInstalled()
   214→        return { success: installed, method: 'binary', error: installed ? undefined : 'Installation completed but bd command not found' }
   215→      }
   216→      return result
   217→    } catch (e: any) {
   218→      beadsAvailable = null
