   244→        if (existingTimer) {
   245→          clearTimeout(existingTimer)
   246→        }
   247→
   248→        const timer = setTimeout(() => {
   249→          debounceTimers.delete(cwd)
   250→          // Emit the tasks-changed event to the renderer
   251→          getMainWindow()?.webContents.send('beads:tasks-changed', { cwd })
   252→        }, DEBOUNCE_DELAY)
