239→async function checkAndUpdateKspec(): Promise<void> {
240→  try {
241→    const localResult = await spawnCommand('kspec', ['--version'], process.cwd())
242→    if (localResult.code !== 0) return
243→    const localVersion = localResult.stdout.trim().replace(/^v/, '')
244→
245→    const npmResult = await spawnCommand('npm', ['view', '@kynetic-ai/spec', 'version'], process.cwd())
246→    if (npmResult.code !== 0) return
247→    const latestVersion = npmResult.stdout.trim()
248→
249→    if (localVersion !== latestVersion) {
250→      console.log(`[kspec] Updating from ${localVersion} to ${latestVersion}...`)
251→      await spawnCommand('npm', ['install', '-g', '@kynetic-ai/spec@latest'], process.cwd())
252→      console.log(`[kspec] Updated to ${latestVersion}`)
253→    }
254→  } catch { /* silent */ }
255→}
256→
257→export function registerKspecHandlers() {
258→  // Check if .kspec/ directory exists in a project
259→  ipcMain.handle('kspec:check', async (_event, cwd: string) => {
260→    const kspecPath = join(cwd, '.kspec')
261→    const exists = existsSync(kspecPath)
262→    return { exists }
263→  })
264→
265→  // Initialize kspec in a project directory
266→  // Requires: git repo, kspec CLI available
267→  ipcMain.handle('kspec:init', async (_event, cwd: string) => {
268→    try {
269→      // Check if it's a git repo first
270→      const gitDir = join(cwd, '.git')
271→      if (!existsSync(gitDir)) {
272→        // Init git first
273→        const gitResult = await spawnCommand('git', ['init'], cwd)
274→        if (gitResult.code !== 0) {
275→          return { success: false, error: `Failed to init git: ${gitResult.stderr}` }
276→        }
277→        // Set default git config for the repo
278→        await spawnCommand('git', ['config', 'user.name', 'kspec'], cwd)
279→        await spawnCommand('git', ['config', 'user.email', 'kspec@local'], cwd)
280→        await spawnCommand('git', ['commit', '--allow-empty', '-m', 'init'], cwd)
281→      }
282→
283→      // Run kspec init
284→      const result = await spawnCommand('kspec', ['init', '.', '--name', 'Project'], cwd)
285→      if (result.code !== 0) {
286→        return { success: false, error: result.stderr || 'kspec init failed' }
287→      }
288→
289→      // Run kspec setup — sets up agent definitions, skills, .agents/ directory
290→      await spawnCommand('kspec', ['setup'], cwd)
291→
292→      // Generate kspec-agents.md — full agent instructions with workflows, conventions, skills
293→      await spawnCommand('kspec', ['agents', 'generate'], cwd)
294→
295→      // Add task instructions to CLAUDE.md pointing at kspec-agents.md
296→      installTaskInstructions(cwd, 'kspec')
297→
298→      return { success: true }
299→    } catch (e) {
300→      return { success: false, error: String(e) }
301→    }
302→  })
303→
304→  // Start kspec daemon if not running
305→  let updateCheckDone = false
306→  ipcMain.handle('kspec:ensure-daemon', async (_event, cwd: string) => {
307→    try {
308→      // Check if daemon is already running
309→      const res = await fetch('http://localhost:3456/api/health').catch(() => null)
310→      if (res?.ok) {
311→        // Register this project with the running daemon
312→        await fetch('http://localhost:3456/api/projects', {
313→          method: 'POST',
314→          headers: { 'Content-Type': 'application/json' },
315→          body: JSON.stringify({ path: cwd })
316→        }).catch(() => {})
317→
318→        // Background update check (once per app session, non-blocking)
319→        if (!updateCheckDone) {
320→          updateCheckDone = true
321→          checkAndUpdateKspec().catch(() => {})
322→        }
323→
324→        return { success: true, alreadyRunning: true }
325→      }
326→
327→      // Start daemon in background
328→      const proc = spawn('kspec', ['serve', 'start', '--daemon'], {
329→        cwd,
330→        env: getExecOptions().env,
331→        detached: true,
332→        stdio: 'ignore'
333→      })
334→      proc.unref()
335→
336→      // Wait for daemon to be ready (up to 5 seconds)
337→      for (let i = 0; i < 10; i++) {
338→        await new Promise(r => setTimeout(r, 500))
339→        const check = await fetch('http://localhost:3456/api/health').catch(() => null)
340→        if (check?.ok) {
341→          return { success: true, alreadyRunning: false }
342→        }
343→      }
344→
345→      return { success: false, error: 'Daemon did not start in time' }
346→    } catch (e) {
347→      return { success: false, error: String(e) }
348→    }
349→  })
350→
351→  // Check if kspec CLI is installed
352→  ipcMain.handle('kspec:check-cli', async () => {
353→    try {
354→      const result = await spawnCommand('kspec', ['--version'], process.cwd())
355→      return { installed: result.code === 0, version: result.stdout.trim() }
356→    } catch {
357→      return { installed: false }
358→    }
359→  })
360→
361→  // Install kspec CLI via npm
362→  ipcMain.handle('kspec:install-cli', async () => {
363→    try {
364→      const result = await spawnCommand('npm', ['install', '-g', '@kynetic-ai/spec'], process.cwd())
365→      if (result.code !== 0) {
366→        return { success: false, error: result.stderr || 'npm install failed' }
367→      }
368→      return { success: true }
369→    } catch (e) {
370→      return { success: false, error: String(e) }
371→    }
372→  })
373→
374→  // Migrate beads tasks to kspec (upgrade path)
375→  ipcMain.handle('kspec:migrate-from-beads', async (_event, cwd: string) => {
376→    return migrateBeadsToKspec(cwd)
377→  })
378→
379→  // Check for kspec updates and install if available
380→  ipcMain.handle('kspec:update', async () => {
381→    try {
382→      // Get installed version
383→      const localResult = await spawnCommand('kspec', ['--version'], process.cwd())
384→      if (localResult.code !== 0) return { updated: false, error: 'kspec not installed' }
385→      const localVersion = localResult.stdout.trim().replace(/^v/, '')
386→
387→      // Get latest version from npm
388→      const npmResult = await spawnCommand('npm', ['view', '@kynetic-ai/spec', 'version'], process.cwd())
389→      if (npmResult.code !== 0) return { updated: false, error: 'Could not check npm' }
390→      const latestVersion = npmResult.stdout.trim()
391→
392→      if (localVersion === latestVersion) {
393→        return { updated: false, current: localVersion, latest: latestVersion }
394→      }
395→
396→      // Update
397→      const updateResult = await spawnCommand('npm', ['install', '-g', '@kynetic-ai/spec@latest'], process.cwd())
398→      if (updateResult.code !== 0) {
399→        return { updated: false, error: updateResult.stderr || 'Update failed', current: localVersion, latest: latestVersion }
400→      }
401→
402→      return { updated: true, previous: localVersion, current: latestVersion }
403→    } catch (e) {
404→      return { updated: false, error: String(e) }
405→    }
406→  })
407→
408→  // Start agent dispatch
409→  ipcMain.handle('kspec:dispatch-start', async (_event, cwd: string) => {
410→    try {
411→      const result = await spawnCommand('kspec', ['agent', 'dispatch', 'start'], cwd)
412→      if (result.code !== 0) {
413→        return { success: false, error: result.stderr || 'Failed to start dispatch' }
414→      }
415→      return { success: true }
416→    } catch (e) {
417→      return { success: false, error: String(e) }
418→    }
419→  })
420→
421→  // Stop agent dispatch
422→  ipcMain.handle('kspec:dispatch-stop', async (_event, cwd: string) => {
423→    try {
424→      const result = await spawnCommand('kspec', ['agent', 'dispatch', 'stop'], cwd)
425→      if (result.code !== 0) {
426→        return { success: false, error: result.stderr || 'Failed to stop dispatch' }
427→      }
428→      return { success: true }
429→    } catch (e) {
430→      return { success: false, error: String(e) }
431→    }
432→  })
433→
434→  // Check agent dispatch status
435→  ipcMain.handle('kspec:dispatch-status', async (_event, cwd: string) => {
436→    try {
437→      const result = await spawnCommand('kspec', ['agent', 'dispatch', 'status', '--json'], cwd)
438→      if (result.code !== 0) {
439→        return { running: false }
440→      }
441→      try {
442→        const data = JSON.parse(result.stdout)
443→        return { running: true, ...data }
444→      } catch {
445→        return { running: result.stdout.toLowerCase().includes('running') }
446→      }
447→    } catch {
448→      return { running: false }
449→    }
450→  })
451→}
