/**
 * Backend Detection
 *
 * Auto-detects which task backend a project uses based on directory contents.
 * Prefers kspec if both are present. Falls back to beads. Returns 'none' if neither.
 */

import type { BackendKind, TaskAdapter } from './types.js'
import { BeadsAdapter } from './beads-adapter.js'
import { KspecAdapter } from './kspec-adapter.js'

// Singleton adapters — stateless enough to reuse
const beadsAdapter = new BeadsAdapter()
const kspecAdapter = new KspecAdapter()

/**
 * Detect which backend is available for a project directory.
 * Checks filesystem via IPC — does not require daemon to be running.
 */
export async function detectBackend(cwd: string): Promise<BackendKind> {
  // Check kspec first (preferred when both exist)
  const kspecStatus = await kspecAdapter.check(cwd)
  if (kspecStatus.initialized) return 'kspec'

  // Check beads
  const beadsStatus = await beadsAdapter.check(cwd)
  if (beadsStatus.installed && beadsStatus.initialized) return 'beads'

  // Neither initialized — check if either is available for init
  if (kspecStatus.installed) return 'none' // could init either
  if (beadsStatus.installed) return 'none'

  return 'none'
}

/**
 * Get the adapter for a given backend kind.
 */
export function getAdapter(kind: BackendKind): TaskAdapter | null {
  switch (kind) {
    case 'beads': return beadsAdapter
    case 'kspec': return kspecAdapter
    default: return null
  }
}

/**
 * Detect backend and return the appropriate adapter.
 * Returns null if no backend is initialized.
 */
export async function getAdapterForProject(cwd: string): Promise<TaskAdapter | null> {
  const kind = await detectBackend(cwd)
  return getAdapter(kind)
}

export { beadsAdapter, kspecAdapter }

import { useState, useEffect, useRef, useCallback } from 'react'
import { tasksCache, beadsStatusCache } from '../../utils/lruCache.js'
import type { UnifiedTask } from './adapters/types.js'
import type { BackendKind, TaskAdapter } from './adapters/types.js'
import { detectBackend, getAdapter, beadsAdapter, kspecAdapter } from './adapters/detect.js'

// Discriminated union for panel state
export type BeadsState =
  | { status: 'loading' }
  | { status: 'not_installed'; installing: 'beads' | 'python' | null; needsPython: boolean; installError: string | null; installStatus: string | null }
  | { status: 'not_initialized'; initializing: boolean; availableBackends: BackendKind[] }
  | { status: 'ready' }
  | { status: 'error'; error: string }

export interface BeadsStateResult {
  beadsState: BeadsState
  setBeadsState: React.Dispatch<React.SetStateAction<BeadsState>>
  tasks: UnifiedTask[]
  setTasks: React.Dispatch<React.SetStateAction<UnifiedTask[]>>
  currentProjectRef: React.MutableRefObject<string | null>
  suppressWatcherReloadRef: React.MutableRefObject<boolean>
  setError: (error: string) => void
  backendKind: BackendKind
  adapter: TaskAdapter | null
}

export function useBeadsState(projectPath: string | null): BeadsStateResult {
  const [beadsState, setBeadsState] = useState<BeadsState>({ status: 'loading' })
  const [tasks, setTasks] = useState<UnifiedTask[]>([])
  const [backendKind, setBackendKind] = useState<BackendKind>('none')
  const currentProjectRef = useRef<string | null>(null)
  const suppressWatcherReloadRef = useRef(false)

  const setError = useCallback((error: string) => {
    setBeadsState({ status: 'error', error })
  }, [])

  // Handle install progress events
  useEffect(() => {
    const cleanup = window.electronAPI?.onInstallProgress((data) => {
      if (data.type === 'python') {
        const percent = data.percent !== undefined ? ` (${data.percent}%)` : ''
        setBeadsState((prev) => {
          if (prev.status !== 'not_installed') return prev
          return { ...prev, installStatus: `${data.status}${percent}` }
        })
      }
    })
    return cleanup
  }, [])

  // Detect backend on project change
  useEffect(() => {
    currentProjectRef.current = projectPath

    if (projectPath) {
      setTasks([])
      setBeadsState({ status: 'loading' })

      // Check cache first
      const cachedTasks = tasksCache.get(projectPath) as UnifiedTask[] | undefined
      const cachedStatus = beadsStatusCache.get(projectPath)
      if (cachedTasks && cachedStatus) {
        setTasks(cachedTasks)
        if (cachedStatus.installed && cachedStatus.initialized) {
          setBeadsState({ status: 'ready' })
        } else if (cachedStatus.installed) {
          setBeadsState({ status: 'not_initialized', initializing: false, availableBackends: ['beads', 'kspec'] })
        } else {
          setBeadsState({ status: 'not_installed', installing: null, needsPython: false, installError: null, installStatus: null })
        }
      }

      // Detect backend
      detectBackend(projectPath).then(kind => {
        if (currentProjectRef.current !== projectPath) return
        setBackendKind(kind)
      })
    } else {
      setTasks([])
      setBackendKind('none')
      setBeadsState({ status: 'loading' })
    }
  }, [projectPath])

  const adapter = getAdapter(backendKind)

  return {
    beadsState,
    setBeadsState,
    tasks,
    setTasks,
    currentProjectRef,
    suppressWatcherReloadRef,
    setError,
    backendKind,
    adapter
  }
}

import React, { useState, useEffect, useCallback } from 'react'
import type { UnifiedTask } from './adapters/types.js'
import { CreateTaskModal } from './CreateTaskModal.js'
import { TaskDetailModal } from './TaskDetailModal.js'
import { BrowserModal } from './BrowserModal.js'
import { StartDropdown } from './StartDropdown.js'
import { BeadsHeader } from './BeadsHeader.js'
import { BeadsInstallView } from './BeadsInstallView.js'
import { BeadsTaskList } from './BeadsTaskList.js'
import { BeadsActionsRow } from './BeadsActionsRow.js'
import { useBeadsState } from './useBeadsState.js'
import { useBeadsTasks } from './useBeadsTasks.js'
import { useBeadsDetail } from './useBeadsDetail.js'
import { useBeadsResize } from './useBeadsResize.js'

const BACKEND_LABELS = {
  beads: 'Beads',
  kspec: 'Kspec',
  none: 'Tasks'
} as const

interface BeadsPanelProps {
  projectPath: string | null
  isExpanded: boolean
  onToggle: () => void
  onStartTaskInNewTab?: (prompt: string) => void
  onSendToCurrentTab?: (prompt: string) => void
  currentTabPtyId?: string | null
}

export function BeadsPanel({
  projectPath,
  isExpanded,
  onToggle,
  onStartTaskInNewTab,
  onSendToCurrentTab,
  currentTabPtyId
}: BeadsPanelProps): React.ReactElement {
  // State management (includes backend detection)
  const {
    beadsState,
    setBeadsState,
    tasks,
    setTasks,
    currentProjectRef,
    suppressWatcherReloadRef,
    setError,
    backendKind,
    adapter
  } = useBeadsState(projectPath)

  // Task CRUD operations (routed through adapter)
  const taskOps = useBeadsTasks({
    projectPath,
    beadsState,
    setBeadsState,
    tasks,
    setTasks,
    currentProjectRef,
    suppressWatcherReloadRef,
    setError,
    adapter,
    backendKind
  })

  // Detail modal (routed through adapter)
  const detailOps = useBeadsDetail({
    projectPath,
    loadTasks: taskOps.loadTasks,
    setError,
    adapter
  })

  // Panel resize
  const { panelHeight, isResizing, handleResizeStart } = useBeadsResize()

  // Agent dispatch state (kspec only)
  const [dispatchRunning, setDispatchRunning] = useState(false)
  const [dispatchToggling, setDispatchToggling] = useState(false)

  // Check dispatch status on mount and when backend changes
  useEffect(() => {
    if (backendKind !== 'kspec' || !projectPath) return
    window.electronAPI?.kspecDispatchStatus?.(projectPath).then(result => {
      setDispatchRunning(!!result?.running)
    }).catch(() => {})
  }, [backendKind, projectPath])

  const handleToggleDispatch = useCallback(async () => {
    if (!projectPath || dispatchToggling) return
    setDispatchToggling(true)
    try {
      if (dispatchRunning) {
        const result = await window.electronAPI?.kspecDispatchStop?.(projectPath)
        if (result?.success) setDispatchRunning(false)
      } else {
        const result = await window.electronAPI?.kspecDispatchStart?.(projectPath)
        if (result?.success) setDispatchRunning(true)
        else setError(result?.error || 'Failed to start dispatch')
      }

/**
 * Project Routes - Beads
 *
 * HTTP endpoints for Beads task management.
 */

import { Router, Request, Response } from 'express'
import { BeadsTask, BeadsCreateRequest, BeadsUpdateRequest } from '../../types.js'
import { getServices } from '../../app.js'
import { sendResponse, sendError } from './helpers.js'

const router = Router()

/**
 * GET /api/projects/beads/check
 * Check if Beads is installed and initialized for a project
 *
 * Query: cwd (required) - project path
 */
router.get('/check', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.beadsCheck) {
      return sendError(res, 503, 'Beads service not available')
    }

    const cwd = req.query.cwd as string
    if (!cwd) {
      return sendError(res, 400, 'cwd query parameter is required')
    }

    const result = await services.beadsCheck(cwd)

    sendResponse(res, 200, {
      success: true,
      data: result,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to check Beads')
  }
})

/**
 * POST /api/projects/beads/init
 * Initialize Beads for a project
 *
 * Body: { cwd: string }
 */
router.post('/init', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.beadsInit) {
      return sendError(res, 503, 'Beads service not available')
    }

    const { cwd } = req.body
    if (!cwd) {
      return sendError(res, 400, 'cwd is required')
    }

    const result = await services.beadsInit(cwd)

    sendResponse(res, result.success ? 200 : 500, {
      success: result.success,
      error: result.error,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to initialize Beads')
  }
})

/**
 * GET /api/projects/beads/tasks
 * List all Beads tasks for a project
 *
 * Query: cwd (required) - project path
 */
router.get('/tasks', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.beadsList) {
      return sendError(res, 503, 'Beads service not available')
    }

    const cwd = req.query.cwd as string
    if (!cwd) {
      return sendError(res, 400, 'cwd query parameter is required')
    }

    const result = await services.beadsList(cwd)

    if (!result.success) {
      return sendError(res, 500, result.error || 'Failed to list tasks')
    }

    sendResponse<BeadsTask[]>(res, 200, {
      success: true,
      data: result.tasks,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to list Beads tasks')
  }
})

/**
 * GET /api/projects/beads/tasks/:taskId
 * Get a specific Beads task
 *
 * Query: cwd (required) - project path
 */
router.get('/tasks/:taskId', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.beadsShow) {
      return sendError(res, 503, 'Beads service not available')
    }

    const { taskId } = req.params
    const cwd = req.query.cwd as string

    if (!cwd) {
      return sendError(res, 400, 'cwd query parameter is required')
    }

    const result = await services.beadsShow(cwd, taskId)

    if (!result.success) {
      return sendError(res, result.error?.includes('not found') ? 404 : 500, result.error || 'Failed to get task')
    }

    sendResponse<BeadsTask>(res, 200, {
      success: true,
      data: result.task,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to get Beads task')
  }
})

/**
 * POST /api/projects/beads/tasks
 * Create a new Beads task
 *
 * Body: { cwd: string, title: string, description?: string, priority?: number, type?: string, labels?: string }
 */
router.post('/tasks', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.beadsCreate) {
      return sendError(res, 503, 'Beads service not available')
    }

    const { cwd, title, description, priority, type, labels }: BeadsCreateRequest & { cwd: string } = req.body

    if (!cwd) {
      return sendError(res, 400, 'cwd is required')
    }
    if (!title) {
      return sendError(res, 400, 'title is required')
    }

    const result = await services.beadsCreate(cwd, title, description, priority, type, labels)

    if (!result.success) {
      return sendError(res, 500, result.error || 'Failed to create task')
    }

    sendResponse<BeadsTask>(res, 201, {
      success: true,
      data: result.task,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to create Beads task')
  }
})

/**
 * PATCH /api/projects/beads/tasks/:taskId
 * Update a Beads task
 *
 * Body: { cwd: string, status?: string, title?: string, description?: string, priority?: number }
 */
router.patch('/tasks/:taskId', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.beadsUpdate) {
      return sendError(res, 503, 'Beads service not available')
    }

    const { taskId } = req.params
    const { cwd, status, title, description, priority }: BeadsUpdateRequest & { cwd: string } = req.body

    if (!cwd) {
      return sendError(res, 400, 'cwd is required')
    }

    const result = await services.beadsUpdate(cwd, taskId, status, title, description, priority)

    sendResponse(res, result.success ? 200 : 500, {
      success: result.success,
      error: result.error,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to update Beads task')
  }
})

/**
 * POST /api/projects/beads/tasks/:taskId/start
 * Start a Beads task (set status to in_progress)
 *
 * Body: { cwd: string }
 */
router.post('/tasks/:taskId/start', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.beadsStart) {
      return sendError(res, 503, 'Beads service not available')
    }

    const { taskId } = req.params
    const { cwd } = req.body

    if (!cwd) {
      return sendError(res, 400, 'cwd is required')
    }

    const result = await services.beadsStart(cwd, taskId)

    sendResponse(res, result.success ? 200 : 500, {
      success: result.success,
      error: result.error,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to start Beads task')
  }
})

/**
 * POST /api/projects/beads/tasks/:taskId/complete
 * Complete a Beads task
 *
 * Body: { cwd: string }
 */
router.post('/tasks/:taskId/complete', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.beadsComplete) {
      return sendError(res, 503, 'Beads service not available')
    }

    const { taskId } = req.params
    const { cwd } = req.body

    if (!cwd) {
      return sendError(res, 400, 'cwd is required')
    }

    const result = await services.beadsComplete(cwd, taskId)

    sendResponse(res, result.success ? 200 : 500, {
      success: result.success,
      data: result.result,
      error: result.error,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to complete Beads task')
  }
})

/**
 * DELETE /api/projects/beads/tasks/:taskId
 * Delete a Beads task
 *
 * Query: cwd (required) - project path
 */
router.delete('/tasks/:taskId', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.beadsDelete) {
      return sendError(res, 503, 'Beads service not available')
    }

    const { taskId } = req.params
    const cwd = req.query.cwd as string

    if (!cwd) {
      return sendError(res, 400, 'cwd query parameter is required')
    }

    const result = await services.beadsDelete(cwd, taskId)

    sendResponse(res, result.success ? 200 : 500, {
      success: result.success,
      error: result.error,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to delete Beads task')
  }
})

export default router

/**
 * Simple LRU (Least Recently Used) cache implementation.
 * Evicts the least recently accessed entry when the cache exceeds maxSize.
 */
export class LRUCache<K, V> {
  private cache: Map<K, V>
  private readonly maxSize: number

  constructor(maxSize: number = 50) {
    if (maxSize < 1) {
      throw new Error('LRU cache maxSize must be at least 1')
    }
    this.cache = new Map()
    this.maxSize = maxSize
  }

  /**
   * Get a value from the cache. Moves the entry to most recently used position.
   */
  get(key: K): V | undefined {
    if (!this.cache.has(key)) {
      return undefined
    }
    // Move to end (most recently used) by re-inserting
    const value = this.cache.get(key)!
    this.cache.delete(key)
    this.cache.set(key, value)
    return value
  }

  /**
   * Set a value in the cache. Evicts LRU entry if cache exceeds maxSize.
   */
  set(key: K, value: V): void {
    // If key exists, delete first to update position
    if (this.cache.has(key)) {
      this.cache.delete(key)
    }

    // Evict LRU entries if we're at capacity
    while (this.cache.size >= this.maxSize) {
      // Map iterator returns entries in insertion order, first is LRU
      const firstKey = this.cache.keys().next().value
      if (firstKey !== undefined) {
        this.cache.delete(firstKey)
      }
    }

    this.cache.set(key, value)
  }

  /**
   * Check if key exists in cache (does not affect LRU order).
   */
  has(key: K): boolean {
    return this.cache.has(key)
  }

  /**
   * Delete a specific key from the cache.
   */
  delete(key: K): boolean {
    return this.cache.delete(key)
  }

  /**
   * Clear all entries from the cache.
   */
  clear(): void {
    this.cache.clear()
  }

  /**
   * Get the current size of the cache.
   */
  get size(): number {
    return this.cache.size
  }

  /**
   * Get all keys in the cache (in LRU order, least recent first).
   */
  keys(): IterableIterator<K> {
    return this.cache.keys()
  }
}

