 12→  CreateTaskParams,
 13→  UpdateTaskParams,
 14→  TaskStatus
 15→} from './types.js'
 16→
 17→const DAEMON_PORT = 3456
 18→const API_BASE = `http://localhost:${DAEMON_PORT}`
 19→
 20→function headers(cwd: string): HeadersInit {
 21→  return {
 22→    'Content-Type': 'application/json',
 23→    'X-Kspec-Dir': cwd
 24→  }
 25→}
 26→
 27→async function api<T>(method: string, path: string, cwd: string, body?: unknown): Promise<T> {
 28→  const opts: RequestInit = {
 29→    method,
 30→    headers: headers(cwd)
 31→  }
 32→  if (body) opts.body = JSON.stringify(body)
 33→  const res = await fetch(`${API_BASE}${path}`, opts)
 34→  if (!res.ok) {
 35→    const text = await res.text()
 36→    throw new Error(text || `HTTP ${res.status}`)
 37→  }
 38→  return res.json()
 39→}
 40→
 41→function normalizeStatus(status: string): TaskStatus {
 42→  switch (status) {
 43→    case 'in_progress': return 'in_progress'
 44→    case 'completed':
 45→    case 'cancelled':
 46→      return 'closed'
 47→    case 'pending':
 48→    case 'blocked':
 49→    case 'pending_review':
 50→    case 'needs_work':
 51→    default:
 52→      return 'open'
 53→  }
 54→}
