 56→function toUnified(raw: Record<string, unknown>): UnifiedTask {
 57→  const tags = Array.isArray(raw.tags) ? raw.tags.map(String) : undefined
 58→  // kspec uses _ulid as primary ID and slugs[] for human-friendly refs
 59→  const slugs = Array.isArray(raw.slugs) ? raw.slugs : []
 60→  // Use slug if available, otherwise full ULID (needed for API calls)
 61→  const id = slugs.length > 0 ? String(slugs[0]) : String(raw._ulid ?? raw.slug ?? raw.id ?? '')
 62→  return {
 63→    id,
 64→    // Short display ID for the UI — slug or first 8 chars of ULID
 65→    displayId: slugs.length > 0 ? String(slugs[0]) : (id.length > 12 ? id.slice(0, 8) : id),
 66→    title: String(raw.title ?? ''),
 67→    status: normalizeStatus(String(raw.status ?? 'pending')),
 68→    priority: typeof raw.priority === 'number' ? raw.priority : undefined,
 69→    type: typeof raw.type === 'string' ? raw.type : undefined,
 70→    description: typeof raw.description === 'string' ? raw.description : undefined,
 71→    created_at: typeof raw.created_at === 'string' ? raw.created_at : undefined,
 72→    updated_at: typeof raw.updated_at === 'string' ? raw.updated_at : undefined,
 73→    tags,
 74→    automation: typeof raw.automation === 'string' ? raw.automation as UnifiedTask['automation'] : undefined,
 75→    _backend: 'kspec'
 76→  }
 77→}
