import { useState, useEffect, useRef, useCallback } from 'react'
import { tasksCache, beadsStatusCache } from '../../utils/lruCache.js'
import type { UnifiedTask } from './adapters/types.js'
import type { BackendKind, TaskAdapter } from './adapters/types.js'
import { detectBackend, getAdapter, beadsAdapter, kspecAdapter } from './adapters/detect.js'

// Discriminated union for panel state
export type BeadsState =
  | { status: 'loading' }
  | { status: 'not_installed'; installing: 'beads' | 'python' | null; needsPython: boolean; installError: string | null; installStatus: string | null }
  | { status: 'not_initialized'; initializing: boolean; availableBackends: BackendKind[] }
  | { status: 'ready' }
  | { status: 'error'; error: string }

export interface BeadsStateResult {
  beadsState: BeadsState
  setBeadsState: React.Dispatch<React.SetStateAction<BeadsState>>
  tasks: UnifiedTask[]
  setTasks: React.Dispatch<React.SetStateAction<UnifiedTask[]>>
  currentProjectRef: React.MutableRefObject<string | null>
  suppressWatcherReloadRef: React.MutableRefObject<boolean>
  setError: (error: string) => void
  backendKind: BackendKind
  adapter: TaskAdapter | null
}

export function useBeadsState(projectPath: string | null): BeadsStateResult {
  const [beadsState, setBeadsState] = useState<BeadsState>({ status: 'loading' })
  const [tasks, setTasks] = useState<UnifiedTask[]>([])
  const [backendKind, setBackendKind] = useState<BackendKind>('none')
  const currentProjectRef = useRef<string | null>(null)
  const suppressWatcherReloadRef = useRef(false)

  const setError = useCallback((error: string) => {
    setBeadsState({ status: 'error', error })
  }, [])

  // Handle install progress events
  useEffect(() => {
    const cleanup = window.electronAPI?.onInstallProgress((data) => {
      if (data.type === 'python') {
        const percent = data.percent !== undefined ? ` (${data.percent}%)` : ''
        setBeadsState((prev) => {
          if (prev.status !== 'not_installed') return prev
          return { ...prev, installStatus: `${data.status}${percent}` }
        })
      }
    })
    return cleanup
  }, [])

  // Detect backend on project change
  useEffect(() => {
    currentProjectRef.current = projectPath

    if (projectPath) {
      setTasks([])
      setBeadsState({ status: 'loading' })

      // Check cache first
      const cachedTasks = tasksCache.get(projectPath) as UnifiedTask[] | undefined
      const cachedStatus = beadsStatusCache.get(projectPath)
      if (cachedTasks && cachedStatus) {
        setTasks(cachedTasks)
        if (cachedStatus.installed && cachedStatus.initialized) {
          setBeadsState({ status: 'ready' })
        } else if (cachedStatus.installed) {
          setBeadsState({ status: 'not_initialized', initializing: false, availableBackends: ['beads', 'kspec'] })
        } else {
          setBeadsState({ status: 'not_installed', installing: null, needsPython: false, installError: null, installStatus: null })
        }
      }

      // Detect backend
      detectBackend(projectPath).then(kind => {
        if (currentProjectRef.current !== projectPath) return
        setBackendKind(kind)
      })
    } else {
      setTasks([])
      setBackendKind('none')
      setBeadsState({ status: 'loading' })
    }
  }, [projectPath])

  const adapter = getAdapter(backendKind)

  return {
    beadsState,
    setBeadsState,
    tasks,
    setTasks,
    currentProjectRef,
    suppressWatcherReloadRef,
    setError,
    backendKind,
    adapter
  }
}

import { useCallback, useEffect, useRef, useState } from 'react'
import { tasksCache, beadsStatusCache } from '../../utils/lruCache.js'
import type { UnifiedTask, TaskAdapter, BackendKind, AutomationEligibility, CreateTaskParams } from './adapters/types.js'
import { detectBackend, getAdapter } from './adapters/detect.js'
import type { BeadsState } from './useBeadsState.js'

export interface TaskCrudCallbacks {
  loadTasks: (showLoading?: boolean) => Promise<void>
  handleInitBeads: () => Promise<void>
  handleInitKspec: () => Promise<void>
  handleUpgradeToKspec: () => Promise<void>
  handleInstallPython: () => Promise<void>
  handleInstallBeads: () => Promise<void>
  handleCreateTask: () => Promise<void>
  handleCompleteTask: (taskId: string) => Promise<void>
  handleDeleteTask: (taskId: string) => Promise<void>
  handleCycleStatus: (taskId: string, currentStatus: string) => Promise<void>
  handleSaveEdit: () => Promise<void>
  handleCancelEdit: () => void
  handleClearCompleted: () => Promise<void>
  upgrading: boolean
}

export interface TaskCrudState {
  showCreateModal: boolean
  setShowCreateModal: React.Dispatch<React.SetStateAction<boolean>>
  newTaskTitle: string
  setNewTaskTitle: React.Dispatch<React.SetStateAction<string>>
  newTaskType: string
  setNewTaskType: React.Dispatch<React.SetStateAction<string>>
  newTaskPriority: number
  setNewTaskPriority: React.Dispatch<React.SetStateAction<number>>
  newTaskDescription: string
  setNewTaskDescription: React.Dispatch<React.SetStateAction<string>>
  newTaskLabels: string
  setNewTaskLabels: React.Dispatch<React.SetStateAction<string>>
  newTaskAutomation: AutomationEligibility | ''
  setNewTaskAutomation: React.Dispatch<React.SetStateAction<AutomationEligibility | ''>>
  editingTaskId: string | null
  setEditingTaskId: React.Dispatch<React.SetStateAction<string | null>>
  editingTitle: string
  setEditingTitle: React.Dispatch<React.SetStateAction<string>>
  editInputRef: React.RefObject<HTMLInputElement>
}

interface UseBeadsTasksParams {
  projectPath: string | null
  beadsState: BeadsState
  setBeadsState: React.Dispatch<React.SetStateAction<BeadsState>>
  tasks: UnifiedTask[]
  setTasks: React.Dispatch<React.SetStateAction<UnifiedTask[]>>
  currentProjectRef: React.MutableRefObject<string | null>
  suppressWatcherReloadRef: React.MutableRefObject<boolean>
  setError: (error: string) => void
  adapter: TaskAdapter | null
  backendKind: BackendKind
}

export function useBeadsTasks({
  projectPath,
  beadsState,
  setBeadsState,
  tasks,
  setTasks,
  currentProjectRef,
  suppressWatcherReloadRef,
  setError,
  adapter,
  backendKind
}: UseBeadsTasksParams): TaskCrudCallbacks & TaskCrudState {
  const [showCreateModal, setShowCreateModal] = useState(false)
  const [newTaskTitle, setNewTaskTitle] = useState('')
  const [newTaskType, setNewTaskType] = useState<string>('task')
  const [newTaskPriority, setNewTaskPriority] = useState<number>(2)
  const [newTaskDescription, setNewTaskDescription] = useState('')
  const [newTaskLabels, setNewTaskLabels] = useState('')
  const [newTaskAutomation, setNewTaskAutomation] = useState<AutomationEligibility | ''>('')
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null)
  const [editingTitle, setEditingTitle] = useState('')
  const editInputRef = useRef<HTMLInputElement>(null)
  const [upgrading, setUpgrading] = useState(false)

  const loadTasks = useCallback(async (showLoading = true) => {
    if (!projectPath) return

    const loadingForProject = projectPath

    if (showLoading) setBeadsState({ status: 'loading' })

    try {
      // Detect backend if we don't have an adapter yet
      const kind = backendKind !== 'none' ? backendKind : await detectBackend(loadingForProject)
      const currentAdapter = kind !== 'none' ? getAdapter(kind) : null

      if (currentProjectRef.current !== loadingForProject) return

      if (!currentAdapter) {
        // Check if beads is at least installable
        const beadsStatus = await window.electronAPI?.beadsCheck(loadingForProject)
        if (currentProjectRef.current !== loadingForProject) return

        if (!beadsStatus?.installed) {
          setBeadsState({ status: 'not_installed', installing: null, needsPython: false, installError: null, installStatus: null })
          return
        }

        // Neither backend initialized — offer choice
        setBeadsState({ status: 'not_initialized', initializing: false, availableBackends: ['beads', 'kspec'] })
        return
      }

      // Backend found — check status
      const status = await currentAdapter.check(loadingForProject)
      if (currentProjectRef.current !== loadingForProject) return

      beadsStatusCache.set(loadingForProject, status)

      if (!status.initialized) {
        setBeadsState({ status: 'not_initialized', initializing: false, availableBackends: [kind] })
        return
      }

      // Load tasks via adapter
      const taskList = await currentAdapter.list(loadingForProject)
      if (currentProjectRef.current !== loadingForProject) return

      setTasks(taskList)
      tasksCache.set(loadingForProject, taskList)
      setBeadsState({ status: 'ready' })
    } catch (e) {
      if (currentProjectRef.current === loadingForProject) {
        setBeadsState({ status: 'error', error: String(e) })
      }
    }
  }, [projectPath, setBeadsState, setTasks, currentProjectRef, backendKind])

  const handleInitBeads = async (): Promise<void> => {
    if (!projectPath) return
    if (beadsState.status !== 'not_initialized') return

    setBeadsState({ status: 'not_initialized', initializing: true, availableBackends: ['beads'] })

    try {
      const result = await window.electronAPI?.beadsInit(projectPath)
      if (result?.success) {
        loadTasks()
      } else {
        setBeadsState({ status: 'error', error: result?.error || 'Failed to initialize beads' })
      }
    } catch (e) {
      setBeadsState({ status: 'error', error: String(e) })
    }
  }

  const handleInitKspec = async (): Promise<void> => {
    if (!projectPath) return
    if (beadsState.status !== 'not_initialized') return

    setBeadsState({ status: 'not_initialized', initializing: true, availableBackends: ['kspec'] })

    try {
      const result = await window.electronAPI?.kspecInit?.(projectPath)
      if (result?.success) {
        // Ensure daemon is running
        await window.electronAPI?.kspecEnsureDaemon?.(projectPath)
        loadTasks()
      } else {
        setBeadsState({ status: 'error', error: result?.error || 'Failed to initialize kspec' })
      }
    } catch (e) {
      setBeadsState({ status: 'error', error: String(e) })
    }
  }

  const handleUpgradeToKspec = async (): Promise<void> => {
    if (!projectPath) return
    setUpgrading(true)

    try {
      // Check if kspec CLI is installed, install if not
      const cliCheck = await window.electronAPI?.kspecCheckCli?.()
      if (!cliCheck?.installed) {
        const installResult = await window.electronAPI?.kspecInstallCli?.()
        if (!installResult?.success) {
          setError(installResult?.error || 'Failed to install kspec CLI')
          setUpgrading(false)
          return
        }
      }

      // Run migration: reads beads tasks, inits kspec, creates tasks, removes .beads/
      const result = await window.electronAPI?.kspecMigrateFromBeads?.(projectPath)
      if (!result?.success) {
        setError(result?.error || 'Migration failed')
        setUpgrading(false)
        return
      }

      // Ensure daemon is running
      await window.electronAPI?.kspecEnsureDaemon?.(projectPath)

      // Clear caches and reload — backend has changed from beads to kspec
      tasksCache.delete(projectPath)
      beadsStatusCache.delete(projectPath)
      loadTasks()
    } catch (e) {
      setError(String(e))
    } finally {
      setUpgrading(false)
    }
  }

  const handleInstallBeads = async (): Promise<void> => {
    setBeadsState({ status: 'not_installed', installing: 'beads', needsPython: false, installError: null, installStatus: null })

    try {
      const result = await window.electronAPI?.beadsInstall()
      if (result?.success) {
        loadTasks()
      } else if (result?.needsPython) {
        setBeadsState({ status: 'not_installed', installing: null, needsPython: true, installError: result.error || 'Python is required', installStatus: null })
      } else {
        setBeadsState({ status: 'not_installed', installing: null, needsPython: false, installError: result?.error || 'Installation failed', installStatus: null })
      }
    } catch (e) {
      setBeadsState({ status: 'not_installed', installing: null, needsPython: false, installError: String(e), installStatus: null })
    }
  }

  const handleInstallPython = async (): Promise<void> => {
    if (beadsState.status !== 'not_installed') return

    setBeadsState({ status: 'not_installed', installing: 'python', needsPython: true, installError: null, installStatus: 'Downloading Python...' })

    try {
      const result = await window.electronAPI?.pythonInstall()
      if (result?.success) {
        setBeadsState({ status: 'not_installed', installing: null, needsPython: false, installError: null, installStatus: null })
        handleInstallBeads()
      } else {
        setBeadsState({ status: 'not_installed', installing: null, needsPython: true, installError: result?.error || 'Python installation failed', installStatus: null })
      }
    } catch (e) {
      setBeadsState({ status: 'not_installed', installing: null, needsPython: true, installError: String(e), installStatus: null })
    }
  }

  const handleCreateTask = async (): Promise<void> => {
    if (!projectPath || !newTaskTitle.trim() || !adapter) return

    try {
      const result = await adapter.create(projectPath, {
        title: newTaskTitle.trim(),
        description: newTaskDescription.trim() || undefined,
        priority: newTaskPriority,
        type: newTaskType as CreateTaskParams['type'],
        tags: newTaskLabels.trim() || undefined,
        automation: newTaskAutomation || undefined
      })
      if (result.success) {
        setNewTaskTitle('')
        setNewTaskType('task')
        setNewTaskPriority(backendKind === 'kspec' ? 3 : 2)
        setNewTaskDescription('')
        setNewTaskLabels('')
        setNewTaskAutomation('')
        setShowCreateModal(false)
        loadTasks()
      } else {
        setError(result.error || 'Failed to create task')
      }
    } catch (e) {
      setError(String(e))
    }
  }

  const handleCompleteTask = async (taskId: string): Promise<void> => {
    if (!projectPath || !adapter) return

    const previousTasks = [...tasks]
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, status: 'closed' as const } : t)
    setTasks(updatedTasks)
    tasksCache.set(projectPath, updatedTasks)

    try {
      const result = await adapter.complete(projectPath, taskId)
      if (!result.success) {
        setTasks(previousTasks)
        tasksCache.set(projectPath, previousTasks)
        setError(result.error || 'Failed to complete task')
      }
    } catch (e) {
      setTasks(previousTasks)
      tasksCache.set(projectPath, previousTasks)
      setError(String(e))
    }
  }

  const handleDeleteTask = async (taskId: string): Promise<void> => {
    if (!projectPath || !adapter) return

    const previousTasks = [...tasks]
    const updatedTasks = tasks.filter(t => t.id !== taskId)
    setTasks(updatedTasks)
    tasksCache.set(projectPath, updatedTasks)

    try {
      const result = await adapter.delete(projectPath, taskId)
      if (!result.success) {
        setTasks(previousTasks)
        tasksCache.set(projectPath, previousTasks)
        setError(result.error || 'Failed to delete task')
      }
    } catch (e) {
      setTasks(previousTasks)
      tasksCache.set(projectPath, previousTasks)
      setError(String(e))
    }
  }

  const handleCycleStatus = async (taskId: string, currentStatus: string): Promise<void> => {
    if (!projectPath || !adapter) return

    let nextStatus: string
    switch (currentStatus) {
      case 'open': nextStatus = 'in_progress'; break
      case 'in_progress': nextStatus = 'closed'; break
      default: nextStatus = 'open'
    }

    const previousTasks = [...tasks]
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, status: nextStatus as UnifiedTask['status'] } : t)
    setTasks(updatedTasks)
    tasksCache.set(projectPath, updatedTasks)

    try {
      const result = await adapter.update(projectPath, taskId, { status: nextStatus as UnifiedTask['status'] })
      if (!result.success) {
        setTasks(previousTasks)
        tasksCache.set(projectPath, previousTasks)
        setError(result.error || 'Failed to update task status')
      }
    } catch (e) {
      setTasks(previousTasks)
      tasksCache.set(projectPath, previousTasks)
      setError(String(e))
    }
  }

  const handleSaveEdit = async (): Promise<void> => {
    if (!projectPath || !editingTaskId || !editingTitle.trim() || !adapter) {
      setEditingTaskId(null)
      return
    }

    const originalTask = tasks.find(t => t.id === editingTaskId)
    if (originalTask && originalTask.title === editingTitle.trim()) {
      setEditingTaskId(null)
      return
    }

    try {
      const result = await adapter.update(projectPath, editingTaskId, { title: editingTitle.trim() })
      if (result.success) {
        loadTasks()
      } else {
        setError(result.error || 'Failed to update task title')
      }
    } catch (e) {
      setError(String(e))
    } finally {
      setEditingTaskId(null)
    }
  }

  const handleCancelEdit = (): void => {
    setEditingTaskId(null)
    setEditingTitle('')
  }

  const handleClearCompleted = async (): Promise<void> => {
    if (!projectPath || !adapter) return

    const closedTasks = tasks.filter(t => t.status === 'closed')
    if (closedTasks.length === 0) return

    const updatedTasks = tasks.filter(t => t.status !== 'closed')
    setTasks(updatedTasks)
    tasksCache.set(projectPath, updatedTasks)

    suppressWatcherReloadRef.current = true

    try {
      await Promise.allSettled(
        closedTasks.map(task => adapter.delete(projectPath, task.id))
      )
    } finally {
      suppressWatcherReloadRef.current = false
    }
  }

  // Set up watcher via adapter
  useEffect(() => {
    const isReady = beadsState.status === 'ready'
    if (!projectPath || !isReady || !adapter) return

    adapter.watch(projectPath)

    const cleanup = adapter.onTasksChanged((data: { cwd: string }) => {
      if (data.cwd === projectPath && !suppressWatcherReloadRef.current) {
        loadTasks(false)
      }
    })

    return () => {
      adapter.unwatch(projectPath)
      cleanup()
    }
  }, [projectPath, beadsState.status, loadTasks, suppressWatcherReloadRef, adapter])

  // Load tasks on mount and when project changes
  useEffect(() => {
    if (projectPath) {
      loadTasks(false)
    }
  }, [projectPath, loadTasks])

  return {
    loadTasks,
    handleInitBeads,
    handleInitKspec,
    handleUpgradeToKspec,
    handleInstallPython,
    handleInstallBeads,
    handleCreateTask,
    handleCompleteTask,
    handleDeleteTask,
    handleCycleStatus,
    handleSaveEdit,
    handleCancelEdit,
    handleClearCompleted,
    showCreateModal,
    setShowCreateModal,
    newTaskTitle,
    setNewTaskTitle,
    newTaskType,
    setNewTaskType,
    newTaskPriority,
    setNewTaskPriority,
    newTaskDescription,
    setNewTaskDescription,
    newTaskLabels,
    setNewTaskLabels,
    newTaskAutomation,
    setNewTaskAutomation,
    editingTaskId,
    setEditingTaskId,
    editingTitle,
    setEditingTitle,
    editInputRef,
    upgrading
  }
}

/**
 * Simple LRU (Least Recently Used) cache implementation.
 * Evicts the least recently accessed entry when the cache exceeds maxSize.
 */
export class LRUCache<K, V> {
  private cache: Map<K, V>
  private readonly maxSize: number

  constructor(maxSize: number = 50) {
    if (maxSize < 1) {
      throw new Error('LRU cache maxSize must be at least 1')
    }
    this.cache = new Map()
    this.maxSize = maxSize
  }

  /**
   * Get a value from the cache. Moves the entry to most recently used position.
   */
  get(key: K): V | undefined {
    if (!this.cache.has(key)) {
      return undefined
    }
    // Move to end (most recently used) by re-inserting
    const value = this.cache.get(key)!
    this.cache.delete(key)
    this.cache.set(key, value)
    return value
  }

  /**
   * Set a value in the cache. Evicts LRU entry if cache exceeds maxSize.
   */
  set(key: K, value: V): void {
    // If key exists, delete first to update position
    if (this.cache.has(key)) {
      this.cache.delete(key)
    }

    // Evict LRU entries if we're at capacity
    while (this.cache.size >= this.maxSize) {
      // Map iterator returns entries in insertion order, first is LRU
      const firstKey = this.cache.keys().next().value
      if (firstKey !== undefined) {
        this.cache.delete(firstKey)
      }
    }

    this.cache.set(key, value)
  }

  /**
   * Check if key exists in cache (does not affect LRU order).
   */
  has(key: K): boolean {
    return this.cache.has(key)
  }

  /**
   * Delete a specific key from the cache.
   */
  delete(key: K): boolean {
    return this.cache.delete(key)
  }

  /**
   * Clear all entries from the cache.
   */
  clear(): void {
    this.cache.clear()
  }

  /**
   * Get the current size of the cache.
   */
  get size(): number {
    return this.cache.size
  }

  /**
   * Get all keys in the cache (in LRU order, least recent first).
   */
  keys(): IterableIterator<K> {
    return this.cache.keys()
  }
}

// Shared cache instances for project data - max 50 projects
const MAX_CACHED_PROJECTS = 50

export const tasksCache = new LRUCache<string, unknown[]>(MAX_CACHED_PROJECTS)
export const beadsStatusCache = new LRUCache<string, { installed: boolean; initialized: boolean }>(MAX_CACHED_PROJECTS)
export const gsdStatusCache = new LRUCache<string, unknown>(MAX_CACHED_PROJECTS)

/**
 * Clear all cached data for a specific project path.
 * Call this when a project is removed from the workspace.
 */
export function clearProjectCaches(projectPath: string): void {
  tasksCache.delete(projectPath)
  beadsStatusCache.delete(projectPath)
  gsdStatusCache.delete(projectPath)
}

import { ipcMain, BrowserWindow } from 'electron'
import { exec, spawn } from 'child_process'
import { promisify } from 'util'
import { existsSync, watch as fsWatch, FSWatcher } from 'fs'
import { join } from 'path'
import { getEnhancedPathWithPortable, setPortableBinDirs } from '../platform'
import { getPortableBinDirs, installBeadsBinary, getBeadsBinaryPath } from '../portable-deps'

const execAsync = promisify(exec)

// File system watchers for .beads directories
const beadsWatchers = new Map<string, FSWatcher>()

// Debounce timers for file change events
const debounceTimers = new Map<string, NodeJS.Timeout>()

// Debounce delay in ms
const DEBOUNCE_DELAY = 500

// Validate taskId to prevent shell command injection
// Task IDs should only contain alphanumeric characters, hyphens, and underscores
const TASK_ID_PATTERN = /^[a-zA-Z0-9_-]+$/
function validateTaskId(taskId: string): void {
  if (!taskId || !TASK_ID_PATTERN.test(taskId)) {
    throw new Error(`Invalid task ID: ${taskId}`)
  }
}

// Execute bd command with arguments using spawn (safer than exec with template literals)
function spawnBdCommand(args: string[], options: { cwd?: string }): Promise<{ stdout: string; stderr: string }> {
  return new Promise((resolve, reject) => {
    const execOptions = getBeadsExecOptions()
    const proc = spawn('bd', args, {
      cwd: options.cwd,
      env: execOptions.env,
      shell: false // Explicitly disable shell to prevent injection
    })

    let stdout = ''
    let stderr = ''

    proc.stdout.on('data', (data) => { stdout += data.toString() })
    proc.stderr.on('data', (data) => { stderr += data.toString() })

    proc.on('close', (code) => {
      if (code === 0) {
        resolve({ stdout, stderr })
      } else {
        const error = new Error(stderr || `Command failed with code ${code}`)
        reject(error)
      }
    })

    proc.on('error', reject)
  })
}

let beadsAvailable: boolean | null = null

function getBeadsExecOptions() {
  const beadsBinPath = getBeadsBinaryPath()
  let PATH = getEnhancedPathWithPortable()
  if (beadsBinPath) {
    PATH = `${beadsBinPath}:${PATH}`
  }
  return {
    shell: process.platform === 'win32' ? true as const : '/bin/bash',
    env: { ...process.env, PATH }
  }
}

async function checkBeadsInstalled(): Promise<boolean> {
  if (beadsAvailable !== null) return beadsAvailable
  beadsAvailable = await execAsync('bd --version', getBeadsExecOptions())
    .then(() => true)
    .catch(() => false)
  return beadsAvailable
}

export function registerBeadsHandlers(getMainWindow: () => BrowserWindow | null) {
  ipcMain.handle('beads:check', async (_, cwd: string) => {
    const installed = await checkBeadsInstalled()
    if (!installed) return { installed: false, initialized: false }
    const beadsDir = join(cwd, '.beads')
    return { installed: true, initialized: existsSync(beadsDir) }
  })

  ipcMain.handle('beads:init', async (_, cwd: string) => {
    try {
      const beadsDir = join(cwd, '.beads')
      if (existsSync(beadsDir)) {
        // Already initialized — don't re-init and risk destroying existing tasks
        return { success: true }
      }
      await execAsync('bd init', { ...getBeadsExecOptions(), cwd })

      // Add unified task instructions to CLAUDE.md
      try {
        const { installTaskInstructions } = await import('./kspec-handlers.js')
        installTaskInstructions(cwd, 'beads')
      } catch { /* non-fatal */ }

      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  ipcMain.handle('beads:ready', async (_, cwd: string) => {
    try {
      const { stdout } = await execAsync('bd ready --json', { ...getBeadsExecOptions(), cwd })
      return { success: true, tasks: JSON.parse(stdout) }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  ipcMain.handle('beads:list', async (_, cwd: string) => {
    try {
      const { stdout } = await execAsync('bd list --json', { ...getBeadsExecOptions(), cwd })
      return { success: true, tasks: JSON.parse(stdout) }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  ipcMain.handle('beads:show', async (_, { cwd, taskId }: { cwd: string; taskId: string }) => {
    try {
      validateTaskId(taskId)
      const { stdout } = await spawnBdCommand(['show', taskId, '--json'], { cwd })
      return { success: true, task: JSON.parse(stdout) }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  ipcMain.handle('beads:create', async (_, { cwd, title, description, priority, type, labels }: { cwd: string; title: string; description?: string; priority?: number; type?: string; labels?: string }) => {
    try {
      // Validate inputs
      if (!title || typeof title !== 'string') {
        return { success: false, error: 'Title is required' }
      }
      if (type && !TASK_ID_PATTERN.test(type)) {
        return { success: false, error: 'Invalid type format' }
      }
      const args = ['create', title]
      if (description) args.push('-d', description)
      if (priority !== undefined) args.push('-p', String(priority))
      if (type) args.push('-t', type)
      if (labels) args.push('-l', labels)
      args.push('--json')
      const { stdout } = await spawnBdCommand(args, { cwd })
      return { success: true, task: JSON.parse(stdout) }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  ipcMain.handle('beads:complete', async (_, { cwd, taskId }: { cwd: string; taskId: string }) => {
    try {
      validateTaskId(taskId)
      const { stdout } = await spawnBdCommand(['close', taskId, '--json'], { cwd })
      return { success: true, result: JSON.parse(stdout) }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  ipcMain.handle('beads:delete', async (_, { cwd, taskId }: { cwd: string; taskId: string }) => {
    try {
      validateTaskId(taskId)
      await spawnBdCommand(['delete', taskId, '--force'], { cwd })
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  ipcMain.handle('beads:start', async (_, { cwd, taskId }: { cwd: string; taskId: string }) => {
    try {
      validateTaskId(taskId)
      await spawnBdCommand(['update', taskId, '--status', 'in_progress'], { cwd })
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  ipcMain.handle('beads:update', async (_, { cwd, taskId, status, title, description, priority }: { cwd: string; taskId: string; status?: string; title?: string; description?: string; priority?: number }) => {
    try {
      validateTaskId(taskId)
      const args = ['update', taskId]
      if (status) args.push('--status', status)
      if (title) args.push('--title', title)
      if (description !== undefined) args.push('--description', description)
      if (priority !== undefined) args.push('--priority', String(priority))
      await spawnBdCommand(args, { cwd })
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  ipcMain.handle('beads:install', async () => {
    try {
      beadsAvailable = null
      const result = await installBeadsBinary((status, percent) => {
        getMainWindow()?.webContents.send('install:progress', { type: 'beads', status, percent })
      })
      if (result.success) {
        const portableDirs = getPortableBinDirs()
        setPortableBinDirs(portableDirs)
        const installed = await checkBeadsInstalled()
        return { success: installed, method: 'binary', error: installed ? undefined : 'Installation completed but bd command not found' }
      }
      return result
    } catch (e: any) {
      beadsAvailable = null
      return { success: false, error: e.message }
    }
  })

  // Start watching a project's .beads directory for changes
  ipcMain.handle('beads:watch', async (_, cwd: string) => {
    // Already watching this project
    if (beadsWatchers.has(cwd)) {
      return { success: true }
    }

    const beadsDir = join(cwd, '.beads')
    if (!existsSync(beadsDir)) {
      return { success: false, error: '.beads directory does not exist' }
    }

    try {
      const watcher = fsWatch(beadsDir, { recursive: true }, (eventType, filename) => {
        // Ignore certain files that shouldn't trigger updates (like lock files, socket files)
        if (filename && (filename.endsWith('.lock') || filename.endsWith('.sock') || filename.includes('.startlock'))) {
          return
        }

        // Debounce: clear existing timer and set a new one
        const existingTimer = debounceTimers.get(cwd)
        if (existingTimer) {
          clearTimeout(existingTimer)
        }

        const timer = setTimeout(() => {
          debounceTimers.delete(cwd)
          // Emit the tasks-changed event to the renderer
          getMainWindow()?.webContents.send('beads:tasks-changed', { cwd })
        }, DEBOUNCE_DELAY)

        debounceTimers.set(cwd, timer)
      })

      watcher.on('error', (err) => {
        console.error(`Beads watcher error for ${cwd}:`, err)
        // Clean up on error
        beadsWatchers.delete(cwd)
      })

      beadsWatchers.set(cwd, watcher)
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // Stop watching a project's .beads directory
  ipcMain.handle('beads:unwatch', async (_, cwd: string) => {
    const watcher = beadsWatchers.get(cwd)
    if (watcher) {
      watcher.close()
      beadsWatchers.delete(cwd)

      // Clear any pending debounce timer
      const timer = debounceTimers.get(cwd)
      if (timer) {
        clearTimeout(timer)
        debounceTimers.delete(cwd)
      }
    }
    return { success: true }
  })
}

